import type { ControlSlug } from "./types";
import { getControl } from "./registry";

const componentDocumentation: Partial<Record<ControlSlug, string>> = {
  "custom-scrollbar": "## Overview\n\nAccessible custom scrollbar with visual tracks and draggable thumbs while retaining native scrolling behaviour.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `orientation` | `\"vertical\" | \"horizontal\" | \"both\"` | `\"vertical\"` | Enabled scroll axes. |\n| `maxHeight` | `number | string` | — | Maximum viewport height. |\n| `autoHide` | `boolean` | `true` | Hides tracks until scrolling begins. |\n| `thickness` | `number` | `10` | Track thickness in pixels. |\n| `minThumbSize` | `number` | `28` | Minimum draggable thumb size. |\n| `verticalTrackShape` | `\"round\" | \"square\"` | `\"round\"` | Vertical track corner style. |\n| `verticalThumbShape` | `\"round\" | \"square\"` | `\"round\"` | Vertical thumb corner style. |\n| `horizontalTrackShape` | `\"round\" | \"square\"` | `\"round\"` | Horizontal track corner style. |\n| `horizontalThumbShape` | `\"round\" | \"square\"` | `\"round\"` | Horizontal thumb corner style. |\n\n## Accessibility\n\n- Retains native wheel, touch, trackpad, and viewport keyboard scrolling.\n- Exposes each thumb with `role=\"scrollbar\"`, orientation, current value, and keyboard controls.\n\n## Related\n\n- [Scroll Area](/documentation/components/scroll-area)",
  "bar-chart-vertical": "## Overview\n\nVertical bar chart powered by the shared `Chart` component.\n\n## When to use\n\n- Comparing one metric across compact categories.\n- Showing simple dashboard totals.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `variant` | `ChartVariant` | — | Selects the visual chart type. |\n| `data` | `ChartDatum[]` | demo data | Category data used by bars, radial, funnel, and point charts. |\n| `series` | `ChartSeries[]` | demo series | Multi-series data used by grouped, stacked, multi-line, and area charts. |\n| `palette` | `ChartPalette` | `\"opus\"` | Opus, cool, warm, or mono palette. |\n| `height` | `number` | `280` | Standard chart viewport height. |\n| `maximise` | `boolean` | `false` | Allows wide chart types such as bars, lines, areas, and point charts to fill available space. |\n| `showGrid` | `boolean` | `false` | Shows chart grid lines where relevant. |\n| `showLegend` | `boolean` | `true` | Shows series/category legend. |\n| `showValues` | `boolean` | `false` | Shows visible value labels where supported. |\n\n## Accessibility\n\n- Renders an SVG with `role=\"img\"` and an accessible label from the chart title.\n- Keep source data available in adjacent tables when exact values matter.",
  "accordion": "## Overview\n\nExpandable section.\n\n## When to use\n\n- FAQs and disclosure.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | \u2014 | Trigger label. |\n| `children` | `ReactNode` | \u2014 | Panel. |\n\n## Accessibility\n\n- `aria-expanded` on trigger.\n\n## Related\n\n- [Accordion group](/documentation/components/accordion-group)",
  "accordion-group": "## Overview\n\nCoordinated accordion items.\n\n## When to use\n\n- FAQ groups.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `type` | `AccordionGroupType` | \u2014 | Single or multiple open. |\n| `children` | `Accordion[]` | \u2014 | Items. |\n\n## Accessibility\n\n- Group has `role=\"group\"`.",
  "button": "## Overview\n\nStandalone action button with multiple visual variants.\n\n## When to use\n\n- Primary actions on forms and dialogs.\n- Secondary or destructive actions when paired with a primary button.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `ReactNode` | \u2014 | Button label or content. |\n| `variant` | `ButtonVariant` | `\"primary\"` | Visual style: primary, secondary, success, danger, warning, info, light, dark, link. |\n| `disabled` | `boolean` | `false` | Disables interaction. |\n| `type` | `\"button\" \\| \"submit\" \\| \"reset\"` | `\"button\"` | Native button type. |\n\n## Accessibility\n\n- Use descriptive button text or `aria-label` when the label is icon-only.",
  "card": "## Overview\n\nCompact content surface.\n\n## When to use\n\n- Dashboard tiles and previews.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | \u2014 | Heading. |\n| `children` | `ReactNode` | \u2014 | Body. |\n\n## Accessibility\n\n- Semantic `article` with `h3`.",
  "stat-card": "## Overview\n\nCompact KPI tile for dashboard summaries.\n\n## When to use\n\n- Headline metrics such as customers, orders, revenue, or active users.\n- Pair multiple stat cards in a grid for at-a-glance dashboards.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `label` | `string` | \u2014 | Metric name. |\n| `value` | `string` | \u2014 | Primary metric value. |\n| `change` | `string` | \u2014 | Optional delta label such as `11.01%`. |\n| `trend` | `\"up\" \\| \"down\"` | \u2014 | Trend direction for the delta badge. |\n| `icon` | `ReactNode` | \u2014 | Optional leading icon. |\n| `density` | `SurfaceDensity` | `\"comfortable\"` | Spacing scale. |\n\n## Accessibility\n\n- Semantic `article` with readable label and value text.",
  "gauge": "## Overview\n\nDashboard progress gauge with half and full variants, optional summary, and footer metrics.\n\n## When to use\n\n- Goal or quota tracking on dashboards.\n- Executive summary cards with one primary progress value.\n- Compact KPI cards where the circular stat is the primary visual.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | \u2014 | Widget heading. |\n| `subtitle` | `string` | \u2014 | Supporting description under the title. |\n| `value` | `number` | \u2014 | Progress percentage from 0\u2013100. |\n| `trackColor` | `string` | theme border | Gauge track stroke colour. |\n| `valueColor` | `string` | Opus accent | Gauge data range stroke colour. |\n| `variant` | `\"half\" \\| \"full\"` | `\"half\"` | Half arc or full circular gauge. |\n| `change` | `string` | \u2014 | Optional delta badge such as `+10%`. |\n| `changeTrend` | `\"up\" \\| \"down\"` | `\"up\"` | Delta badge direction. |\n| `summary` | `string` | \u2014 | Supporting copy below the gauge. |\n| `footer` | `{ color?, label, value, trend? }[]` | \u2014 | Optional footer metrics. Each item can define its own accent line colour. |\n| `density` | `SurfaceDensity` | `\"comfortable\"` | Spacing scale. |",
  "pipeline-overview": "## Overview\n\nSales pipeline funnel with neon glass stage bars, legend, total value, and period selector. Wrap in `DashboardContentContainer` for the dashboard section shell.\n\n## When to use\n\n- CRM pipeline dashboards.\n- Executive summaries of stage value and conversion mix.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `stages` | `PipelineStage[]` | \u2014 | Stage label, value, display value, and percentage. |\n| `totalLabel` | `string` | `\"Total Pipeline Value\"` | Footer total caption. |\n| `totalValue` | `string` | \u2014 | Formatted total pipeline value. |\n| `period` | `string` | `\"This Month\"` | Selected period label. |\n| `periodOptions` | `string[]` | month presets | Period dropdown options. |\n| `onPeriodChange` | `(period) => void` | \u2014 | Called when the period dropdown selection changes. |",
  "deals-over-time": "## Overview\n\nDeals over time line chart with neon spline, area fill, hover tooltip, and period selector. Supports purple or blue palette. Wrap in `DashboardContentContainer` for the dashboard section shell.\n\n## When to use\n\n- CRM deal volume trends on dashboards.\n- Executive summaries of monthly or quarterly deal activity.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | `\"Deals Over Time\"` | Widget heading shown in the header row. |\n| `data` | `DealsOverTimePoint[]` | \u2014 | Chart points with `label`, `value`, and optional `tooltipLabel`. |\n| `maxValue` | `number` | `100` | Y-axis maximum value. |\n| `valueLabel` | `string` | `\"Deals\"` | Tooltip value suffix. |\n| `period` | `string` | `\"This Year\"` | Selected period label. |\n| `periodOptions` | `string[]` | period presets | Period dropdown options. |\n| `palette` | `\"purple\" \\| \"blue\"` | `\"purple\"` | Chart color theme (neon purple or blue). |\n| `onPeriodChange` | `(period) => void` | \u2014 | Called when the period dropdown selection changes. |",
  "upcoming-tasks": "## Overview\n\nUpcoming tasks list for dashboard CRM views with checkbox rows, subtitles, and due times.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | `\"Upcoming Tasks\"` | Widget heading. |\n| `tasks` | `UpcomingTaskItem[]` | \u2014 | Task title, subtitle, time, and optional `completed`. |\n| `checkboxSize` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Checkbox control size. |\n| `footerLabel` | `string` | `\"View all tasks\"` | Footer link label. |\n| `onFooterClick` | `() => void` | \u2014 | Called when the footer link is clicked. |\n| `onTaskClick` | `(task) => void` | \u2014 | Called when a task row is clicked. |\n| `onTaskCompleteChange` | `(task, completed) => void` | \u2014 | Called when a task checkbox is toggled. |\n| `footerHref` | `string` | \u2014 | Optional href; when set, renders a link instead of the callback button. |",
  "recent-activity": "## Overview\n\nRecent activity feed for dashboard CRM views with icon rows and relative timestamps.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | `\"Recent Activity\"` | Widget heading. |\n| `items` | `RecentActivityItem[]` | \u2014 | Activity title, subtitle, icon, tone, and time. |\n| `footerLabel` | `string` | `\"View all activity\"` | Footer link label. |\n| `onFooterClick` | `() => void` | \u2014 | Called when the footer link is clicked. |\n| `onItemClick` | `(item) => void` | \u2014 | Called when an activity row is clicked. |\n| `footerHref` | `string` | \u2014 | Optional href; when set, renders a link instead of the callback button. |",
  columns: "## Overview\n\nEqual-width column layout for placing children side by side or stacked in one column.\n\n## When to use\n\n- Dashboard rows with multiple widgets of equal width.\n- Any page section that needs two, three, or more columns with consistent sizing.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `direction` | `\"row\" \\| \"column\"` | `\"row\"` | Row places children in equal columns; column stacks them. |\n| `columns` | `number` | `3` | Number of equal columns when `direction` is `row`. |\n| `gap` | `number \\| string` | `16` | Gap between columns. |\n| `children` | `ReactNode` | \u2014 | Column content. |\n| `className` | `string` | \u2014 | Optional class name on the root container. |\n\n## Related\n\n- [Grid](/documentation/components/grid)\n- [Stack](/documentation/components/stack)",
  "lab-dashboard-list-columns": "## Overview\n\nLabs composition that places upcoming tasks, recent activity, and top performing people side by side. Built with the `Columns` layout and `DashboardContentContainer` widgets.\n\n## When to use\n\n- Reference pattern for a three-column CRM dashboard row.\n- Starting point before customising titles, data, and callbacks.\n\n## Composition\n\n```tsx\n<Columns direction=\"row\" columns={3} gap={16}>\n  <DashboardContentContainer data-component=\"upcoming-tasks\" width=\"full\">\n    <UpcomingTasks ... />\n  </DashboardContentContainer>\n  <DashboardContentContainer data-component=\"recent-activity\" width=\"full\">\n    <RecentActivity ... />\n  </DashboardContentContainer>\n  <DashboardContentContainer data-component=\"top-performing-users\" width=\"full\">\n    <TopPerformingUsers ... />\n  </DashboardContentContainer>\n</Columns>\n```\n\n## Related\n\n- [Columns](/documentation/components/columns)\n- [Upcoming Tasks](/documentation/components/upcoming-tasks)\n- [Recent Activity](/documentation/components/recent-activity)\n- [Top Performing People](/documentation/components/top-performing-users)\n- [Dashboard Content Container](/documentation/components/dashboard-content-container)",
  "lab-notes-activity": "## Overview\n\nLabs composition for CRM notes and activity. Combines tabbed navigation, a top-level `NoteComposer` for new notes, per-note `+` actions to open an inline thread reply composer, `ContentTimeline` with `Avatar` rails, nested note comments, tag pills, and tab-specific footer links inside `DashboardContentContainer`.\n\n## When to use\n\n- Deal or contact detail side panels.\n- CRM activity history with quick note capture.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `NotesActivityItem[]` | — | Feed entries with author, body, time, date group, kind, optional tags, and optional nested `comments`. |\n| `addNoteButtonLabel` | `string` | `\"Add note\"` | Label shown above an active thread reply composer when the note already has replies. |\n| `composerPlaceholder` | `string` | `\"Add a note...\"` | Placeholder passed to the top-level `NoteComposer`. |\n| `saveButtonLabel` | `string` | `\"Save Note\"` | Save action label passed to the top-level `NoteComposer`. |\n| `density` | `SurfaceDensity` | `\"comfortable\"` | Controls internal spacing for compact or comfortable dashboard layouts. |\n| `noteAuthorName` | `string` | `\"You\"` | Author used for locally-created top-level and nested notes. |\n| `noteAuthorAvatarSrc` | `string` | — | Optional avatar used for locally-created top-level and nested notes. |\n| `notesFooterLabel` | `string` | `\"View all notes\"` | Footer label shown on the Notes tab. |\n| `activityFooterLabel` | `string` | `\"View all activities\"` | Footer label shown on the Activity tab. |\n| `onNoteAttachClick` | `() => void` | — | Called when the composer attach control is pressed. |\n| `onNoteMentionClick` | `() => void` | — | Called when the composer mention control is pressed. |\n| `onNoteEmojiSelect` | `(emoji) => void` | — | Called when an emoji is inserted. |\n| `onNotesFooterClick` | `() => void` | — | Called when the Notes footer link is clicked. |\n| `onActivityFooterClick` | `() => void` | — | Called when the Activity footer link is clicked. |\n| `onItemClick` | `(item) => void` | — | Called when a feed row is clicked. |\n| `onNoteSave` | `(note, parentNote?) => void` | — | Called when Save Note or Reply is pressed. `parentNote` is set for nested replies and omitted for top-level notes. |\n| `onTabChange` | `(tab) => void` | — | Called when Notes or Activity tab changes. |\n| `notesFooterHref` | `string` | — | Optional Notes tab href; when set, renders a link instead of the callback button. |\n| `activityFooterHref` | `string` | — | Optional Activity tab href; when set, renders a link instead of the callback button. |\n\n## Related\n\n- [Note composer](/documentation/components/note-composer)\n- [Content timeline](/documentation/components/content-timeline)\n- [Dashboard Content Container](/documentation/components/dashboard-content-container)",
  "404-page": "## Overview\n\nNot-found error page content using `ErrorPage`. Usage and Playground show the same source.\n\n## When to use\n\n- Next.js `not-found.tsx` handlers.\n- Broken links or removed documentation routes.\n\n## Production route\n\nWrap the same JSX in `app/not-found.tsx`, or use `NotFoundPage` when you need the full documentation shell.\n\n## Related\n\n- [403 Page](/documentation/components/403-page)",
  "403-page": "## Overview\n\nAccess-denied error page content using `ErrorPage`. Usage and Playground show the same source.\n\n## When to use\n\n- Authorisation failures and role-gated pages.\n- Previewing forbidden states during product design.\n\n## Production route\n\nWrap the same JSX in your forbidden route, or use `ForbiddenPage` when you need the full documentation shell.\n\n## Related\n\n- [404 Page](/documentation/components/404-page)",
  "app-setup": "## Overview\n\nRunnable app shell wiring with `ThemeProvider`, `PortalHost`, and a drawer demo. Usage and Playground show the same source.\n\n## When to use\n\n- Bootstrapping a new app that consumes `opus-react`.\n- Ensuring portalled overlays (drawers, modals, dropdowns) inherit theme tokens.\n\n## Production Next.js setup\n\nDrop the Usage/Playground component into `app/page.tsx`, then add global styles and fonts in `app/layout.tsx`:\n\n- Import `opus-react/styles.css` and `opus-react/index.css`.\n- Set `data-theme` on `<html>`.\n- Wrap `{children}` in your own `OpusAppShell` client component (`ThemeProvider` + optional `PortalHost`).\n\n## Portalled components\n\nThese render outside the React parent tree automatically — no manual `<Portal>` wrapper required in usage code:\n\n- **Full-screen overlays:** Drawer, Dialog, Modal, Command palette, Lightbox, Model lightbox\n- **Floating UI:** Dropdown menu, Mega menu, Tooltip, Context menu, Emoji picker\n\nUse the standalone [Portal](/documentation/components/portal) utility when building custom overlays.\n\n## Related\n\n- [Theme provider](/documentation/components/theme-provider)\n- [Portal host](/documentation/components/portal-host)",
  "top-performing-users": "## Overview\n\nTop performing people leaderboard with avatars, gradient performance bars, and values.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | `\"Top Performing People\"` | Widget heading. |\n| `users` | `TopPerformingUserItem[]` | \u2014 | Person name, value, and display value. |\n| `footerLabel` | `string` | `\"View full report\"` | Footer link label. |\n| `onFooterClick` | `() => void` | \u2014 | Called when the footer link is clicked. |\n| `onPersonClick` | `(person) => void` | \u2014 | Called when a person row is clicked. |\n| `footerHref` | `string` | \u2014 | Optional href; when set, renders a link instead of the callback button. |",
  "user-profile": "## Overview\n\nCompact signed-in user profile row for dashboard headers and account menus. Shows avatar, name, role, and a chevron dropdown. The widget does not own photo upload \u2014 the parent composes `ProfilePhotoUploadModal` and wires menu `onSelect` callbacks to open it.\n\n## When to use\n\n- Dashboard account switcher or profile menu trigger.\n- Header identity chip with name, role, and account actions.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `name` | `string` | \u2014 | Display name. |\n| `role` | `string` | \u2014 | Secondary label such as role or team. |\n| `src` | `string` | \u2014 | Optional profile photo URL. |\n| `avatarSize` | `AvatarSize` | `\"md\"` | Avatar scale. |\n| `menuItems` | `UserProfileMenuItem[]` | `[]` | Dropdown entries with `id`, `label`, optional `destructive`, and `onSelect` callback. |\n| `onAvatarClick` | `() => void` | \u2014 | Optional avatar click handler defined by the parent. |\n| `onMenuSelect` | `(item) => void` | \u2014 | Called after each menu item's `onSelect` handler runs. |\n\n## Usage\n\n```tsx\nconst [photo, setPhoto] = useState(\"/user-profile-carl.png\");\nconst [photoUploadOpen, setPhotoUploadOpen] = useState(false);\nconst openPhotoUpload = () => setPhotoUploadOpen(true);\n\nconst menuItems = [\n  { id: \"change-avatar\", label: \"Change Avatar\", onSelect: openPhotoUpload },\n  { id: \"profile\", label: \"Profile\", onSelect: () => navigate(\"/profile\") },\n];\n\n<>\n  <UserProfileWidget\n    name=\"Carl Fearby\"\n    role=\"Administrator\"\n    src={photo}\n    menuItems={menuItems}\n    onAvatarClick={openPhotoUpload}\n  />\n  <ProfilePhotoUploadModal\n    fieldId=\"profile-photo-upload\"\n    open={photoUploadOpen}\n    value={photo}\n    onClose={() => setPhotoUploadOpen(false)}\n    onPhotoChange={setPhoto}\n  />\n</>\n```\n\n## Dashboard vs Labs\n\n- **Dashboard** \u2014 use `UserProfileWidget` directly in headers and toolbars.\n- **Labs** \u2014 wrap in `<DashboardContentContainer data-component=\"user-profile\" width=\"widget\">`.\n\n## Related\n\n- [Image crop upload](/documentation/components/image-crop-upload)\n\n## Accessibility\n\n- Avatar button exposes an accessible name when `onAvatarClick` is provided.\n- Chevron trigger exposes an accessible name.\n- Menu items are keyboard navigable via `DropdownMenu`.",
  "profile-photo-upload": "## Overview\n\nDashboard widget for profile photo capture. Wraps `ImageCropUploadField` with an optional title and circular crop workflow before upload.\n\n## When to use\n\n- Account settings panels and profile editors.\n- Dashboard flows that need framed avatar uploads.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | \u2014 | Optional widget heading above the field. |\n| `label` | `string` | `\"Profile photo\"` | Field label passed to the crop control. |\n| `value` | `string` | \u2014 | Cropped preview URL after apply. |\n| `onChange` | `(previewUrl) => void` | \u2014 | Called with the cropped preview URL. |\n| `onCrop` | `({ file, previewUrl }) => void` | \u2014 | Called with the cropped `File` and preview URL. |\n| `viewportSize` | `number` | `240` | Circular editor diameter in pixels. |\n| `outputSize` | `number` | `256` | Exported crop size in pixels. |\n\n## Related\n\n- [Image crop upload](/documentation/components/image-crop-upload)",
  "dashboard-content-container":
    "## Overview\n\nNeon glass dashboard section shell. Pass any dashboard widget or JSX as children.\n\n## When to use\n\n- Wrapping dashboard widgets in a consistent section frame.\n- Building custom dashboard layouts that match Pipeline Overview styling.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | \u2014 | Optional section heading. |\n| `width` | `\"widget\" \\| \"full\"` | `\"widget\"` | Fixed widget width or full-width section. |\n| `height` | `\"auto\" \\| \"full\"` | `\"auto\"` | Auto content height or fill the available preview/container height. |\n| `paddingTop` | `boolean` | `true` | Enables the container's top padding. |\n| `paddingRight` | `boolean` | `true` | Enables the container's right padding. |\n| `paddingBottom` | `boolean` | `true` | Enables the container's bottom padding. |\n| `paddingLeft` | `boolean` | `true` | Enables the container's left padding. |\n| `children` | `ReactNode` | \u2014 | Dashboard content to render inside the shell. |\n| `className` | `string` | \u2014 | Optional class name on the root container. |",
  "carousel": "## Overview\n\nImage carousel with nav and pips.\n\n## When to use\n\n- Hero rotators and galleries.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `images` | `GalleryImage[]` | \u2014 | Slides. |\n| `loop` | `boolean` | \u2014 | Wrap slides. |\n\n## Accessibility\n\n- Keyboard arrows; live region for slide.\n\n## Related\n\n- [Lightbox](/documentation/components/lightbox)",
  "checkbox": "## Overview\n\nBoolean checkbox with round or square shape variants.\n\n## When to use\n\n- Single on/off preferences.\n- Options that do not require a radio group.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `checked` | `boolean` | \u2014 | Controlled checked state. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `shape` | `\"round\" \\| \"square\"` | `\"square\"` | Checkbox shape. |\n| `size` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Checkbox and tick scale. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.\n- Uses native checkbox with visible label.",
  "color-picker": "## Overview\n\nColour input with swatch and hex display.\n\n## When to use\n\n- Theme or branding pickers.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Hex colour. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.\n- `aria-valuetext` announces hex value.",
  "command-palette": "## Overview\n\nSearchable command launcher.\n\n## When to use\n\n- Global shortcuts and actions.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `open` | `boolean` | \u2014 | Visible. |\n| `items` | `CommandPaletteItem[]` | \u2014 | Commands. |\n| `onClose` | `() => void` | \u2014 | Close handler. |\n\n## Accessibility\n\n- Combobox search with focus trap.",
  "context-menu": "## Overview\n\nRight-click pointer menu.\n\n## When to use\n\n- Contextual row/card actions.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `DropdownMenuItemData[]` | \u2014 | Items. |\n| `label` | `string` | \u2014 | Target label. |\n\n## Accessibility\n\n- Requires `ContextMenuProvider`. Shift+F10 opens menu.\n\n## Related\n\n- [Dropdown menu](/documentation/components/dropdown-menu)",
  "data-grid": "## Overview\n\nScrollable data grid with sort, filter, and structural layouts.\n\n## Layouts\n\n| Layout | Behaviour |\n| --- | --- |\n| `flat` | Default dense row list. |\n| `grouped` | Collapse rows by `groupBy` with expandable group headers. |\n| `tree` | Nested `row.children` with indent and expand toggles. |\n| `pivot` | Client pivot via `pivot` aggregator into synthetic columns. |\n\n## Scale features\n\n- **Master detail** — `getDetailContent` inserts a full-width detail row.\n- **Virtualized** — window visible rows with fixed `rowHeight`.\n- **Infinite** — `hasMore` / `onLoadMore` sentinel at the scroll bottom.\n\n## When to use\n\n- Large datasets that need sort/filter and optional tree, group, pivot, or virtualization.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `columns` | `DataGridColumn[]` | — | Columns. |\n| `rows` | `DataGridRow[]` | — | Rows (optional nested `children`). |\n| `layout` | `\"flat\" \\| \"grouped\" \\| \"tree\" \\| \"pivot\"` | `\"flat\"` | Structural mode. |\n| `groupBy` | `string` | — | Group column key when grouped. |\n| `pivot` | `DataGridPivotConfig` | — | Pivot dimensions and aggregator. |\n| `getDetailContent` | `(row) => ReactNode` | — | Master-detail body. |\n| `virtualized` | `boolean` | `false` | DOM windowing. |\n| `hasMore` / `onLoadMore` | infinite load | — | Bottom sentinel. |\n\n## Accessibility\n\n- `aria-sort` on sortable headers.\n- Expand controls expose `aria-expanded`.",
  "date-picker": "## Overview\n\nNative date input (`type=\"date\"`).\n\n## When to use\n\n- Date selection with browser-native picker.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Input value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "datetime-picker": "## Overview\n\nNative date and time input (`type=\"datetime-local\"`).\n\n## When to use\n\n- Date and time selection with browser-native picker.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Input value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "dialog": "## Overview\n\nConfirmation dialog with preset action sets.\n\n## When to use\n\n- Confirmations and destructive gates.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `open` | `boolean` | \u2014 | Visible. |\n| `title` | `string` | \u2014 | Heading. |\n| `description` | `string` | \u2014 | Message. |\n| `actionSet` | `DialogActionSet` | \u2014 | Buttons preset. |\n| `onClose` | `() => void` | \u2014 | Close handler. |\n\n## Accessibility\n\n- Focus trap, dialog role, scroll lock.",
  "drawer": "## Overview\n\nEdge-attached overlay panel. Renders through an internal portal so it stacks above app chrome and nested stacking contexts.\n\n## When to use\n\n- Filters, inspectors, nav.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `open` | `boolean` | \u2014 | Visible. |\n| `title` | `string` | \u2014 | Heading. |\n| `side` | `DrawerSide` | `\"right\"` | Edge. |\n| `onClose` | `() => void` | \u2014 | Close handler. |\n\n## Accessibility\n\n- Focus trap and restore on close.",
  "dropdown-menu": "## Overview\n\nAnchored action menu.\n\n## When to use\n\n- Toolbar and nav menus.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `DropdownMenuItemData[]` | \u2014 | Menu items. |\n| `label` | `string` | \u2014 | Trigger label. |\n| `placement` | `DropdownMenuPlacement` | \u2014 | Position. |\n\n## Accessibility\n\n- Arrow keys, Home, End, Escape.",
  "email-input": "## Overview\n\nEmail variant of TextField.\n\n## When to use\n\n- Collecting email values.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `placeholder` | `string` | \u2014 | Placeholder. |\n| `type` | `\"email\"` | `\"email\"` | Fixed input type. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "empty-state": "## Overview\n\nEmpty list placeholder for first-use screens, cleared collections, and **search with zero results**.\n\n## When to use\n\n- Zero results and onboarding.\n- Empty filtered/search states (`icon=\"search\"`).\n\n## Empty search recipe\n\nReuse `EmptyState` — do not introduce a separate empty-search component:\n\n```tsx\n<EmptyState\n  icon=\"search\"\n  title=\"No results for your search\"\n  description=\"Try a different keyword or clear filters to broaden the results.\"\n  actions={<Button variant=\"secondary\">Clear search</Button>}\n/>\n```\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | \u2014 | Heading. |\n| `description` | `string` | \u2014 | Guidance. |\n| `icon` | `string \\| false` | `\"inbox\"` | Catalog icon name, or `false` to hide. |\n| `actions` | `ReactNode` | \u2014 | Optional CTA row. |\n| `density` | `SurfaceDensity` | `\"comfortable\"` | Spacing scale. |\n\n## Accessibility\n\n- Labelled `section`.",
  badge: "## Overview\n\nCompact label for status, category, or count chips.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `label` | `string` | \u2014 | Badge text. |\n| `tone` | `BadgeTone` | `\"neutral\"` | Colour intent. |\n| `variant` | `BadgeVariant` | `\"soft\"` | solid, soft, or outline. |\n| `size` | `BadgeSize` | `\"md\"` | Visual scale. |\n| `dot` | `boolean` | `false` | Leading status dot. |",
  avatar: "## Overview\n\nUser or entity avatar with image or initials.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `name` | `string` | \u2014 | Accessible name and initials source. |\n| `src` | `string` | \u2014 | Optional image URL. |\n| `size` | `AvatarSize` | `\"md\"` | sm to xl. |\n| `shape` | `AvatarShape` | `\"circle\"` | circle or rounded. |",
  "avatar-group": "## Overview\n\nStacked avatars with overflow count.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `{ name, src? }[]` | \u2014 | People. |\n| `max` | `number` | `4` | Visible avatars before +N. |\n| `size` | `AvatarSize` | `\"md\"` | Shared size. |",
  list: "## Overview\n\nStructured content list with optional icons and meta.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `ListItem[]` | \u2014 | Rows. |\n| `density` | `SurfaceDensity` | `\"comfortable\"` | Spacing. |\n| `ordered` | `boolean` | `false` | Numbered list. |",
  "description-list": "## Overview\n\nTerm/details metadata list.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `{ term, details }[]` | \u2014 | Pairs. |\n| `layout` | `\"stacked\" \\| \"inline\"` | `\"stacked\"` | Arrangement. |",
  divider: "## Overview\n\nSection separator.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `orientation` | `\"horizontal\" \\| \"vertical\"` | `\"horizontal\"` | Axis. |\n| `label` | `string` | \u2014 | Optional centred label. |\n| `tone` | `DividerTone` | `\"default\"` | Visual weight. |",
  "content-timeline": "## Overview\n\nVertical activity timeline (distinct from chart Timeline). Supports dot rails for simple events or avatar rails for people-centric feeds, optional tag labels, and grouped section headings.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `ContentTimelineItem[]` | — | Flat timeline events with title, optional description, time, status, tags, and avatar metadata. |\n| `groups` | `ContentTimelineGroup[]` | — | Optional grouped sections with a section `label` and nested `items`. |\n| `onItemClick` | `(item, index) => void` | — | Called when a timeline row is clicked. |\n\n## Item fields\n\n| Field | Type | Description |\n| --- | --- | --- |\n| `title` | `string` | Primary row heading. |\n| `description` | `string` | Supporting body copy. |\n| `time` | `string` | Optional timestamp. |\n| `tags` | `ContentTimelineTag[]` | Optional label pills shown below the description. |\n| `avatarName` | `string` | When set, renders an avatar marker instead of a status dot. |\n| `status` | `ContentTimelineStatus` | Dot accent when no avatar is shown. |",
  "tree-view": "## Overview\n\nExpandable tree hierarchy.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `nodes` | `TreeViewNode[]` | \u2014 | Nested nodes. |\n| `defaultExpandedIds` | `string[]` | \u2014 | Initially open ids. |",
  "masonry-grid": "## Overview\n\nMulti-column masonry layout.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `MasonryGridItem[]` | \u2014 | Cards. |\n| `columns` | `number` | `3` | 2\u20134 columns. |\n| `gap` | `number` | `12` | Column/card gap. |",
  "property-grid": "## Overview\n\nDense key/value inspector.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `PropertyGridItem[]` | \u2014 | Rows (`copyable` optional). |\n| `bordered` | `boolean` | `false` | Outer frame around the grid. |",
  stack: "## Overview\n\nFlex stack for spacing children in a row or column.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `direction` | `\"row\" \\| \"column\"` | `\"column\"` | Axis. |\n| `gap` | `number \\| string` | `12` | Spacing between children. |\n| `align` / `justify` | alignment tokens | stretch / start | Cross and main axis. |\n| `wrap` | `boolean` | `false` | Allow wrapping. |",
  grid: "## Overview\n\nResponsive CSS grid.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `columns` | `number \\| string` | `3` | Explicit columns when `minItemWidth` is unset. |\n| `gap` | `number \\| string` | `12` | Grid gap. |\n| `minItemWidth` | `number \\| string` | \u2014 | Auto-fit minmax columns. |",
  splitter: "## Overview\n\nTwo panes with a draggable separator.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `[ReactNode, ReactNode]` | \u2014 | Left/top and right/bottom panes. |\n| `orientation` | `\"horizontal\" \\| \"vertical\"` | `\"horizontal\"` | Split axis. |\n| `defaultSize` | `number` | `40` | Primary pane size (%). |",
  "resize-handle": "## Overview\n\nShared separator control for draggable layout boundaries. Splitter and Three Pane Layout use this primitive so resize styling, hover expansion, and separator semantics stay consistent.\n\nResizeHandle is intentionally parent-controlled: the parent owns pane size state, pointer drag logic, keyboard resize increments, and layout CSS. The handle renders the accessible control surface and receives the parent callbacks plus current `aria-valuemin`, `aria-valuemax`, and `aria-valuenow` values.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `orientation` | `\"horizontal\" \\| \"vertical\"` | \u2014 | Axis of the resize separator. |\n| `background` | `\"subtle\" \\| \"accent\" \\| \"contrast\" \\| \"none\"` | `\"subtle\"` | Strip background treatment. |\n| `height` | `\"short\" \\| \"medium\" \\| \"tall\" \\| \"full\"` | `\"medium\"` | Grip marker length before hover/focus expansion. |\n| `onPointerDown` | `PointerEventHandler` | \u2014 | Parent resize starter. |\n| `onKeyDown` | `KeyboardEventHandler` | \u2014 | Parent keyboard resize handler. |\n\n## Accessibility\n\n- Renders as a `button` with `role=\"separator\"`.\n- Parent components should pass current size aria values and keyboard resize behaviour when the handle controls a pane.",
  "resizable-panel": "## Overview\n\nPanel with a bottom-right resize handle.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `defaultWidth` / `defaultHeight` | `number` | `320` / `200` | Initial size. |\n| `minWidth` / `maxWidth` | `number` | bounds | Clamp width. |\n| `onResize` | `(size) => void` | \u2014 | Size change handler. |",
  "dock-layout": "## Overview\n\nIDE-style docked regions around a main pane.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `top` / `left` / `right` / `bottom` | `ReactNode` | \u2014 | Optional docks. |\n| `children` | `ReactNode` | \u2014 | Centre content. |",
  "three-pane-layout": "## Overview\n\nApplication shell with optional left and right sidebars around a central content area. Sidebars resize with keyboard-accessible drag handles and can persist their widths in localStorage.\n\n## When to use\n\n- Editor or dashboard shells with navigation on the left and inspector/details on the right.\n- Workspaces where users should be able to tune pane widths and keep them between visits.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `left` / `right` | `ReactNode` | \u2014 | Optional sidebar content. |\n| `children` | `ReactNode` | \u2014 | Main centre pane content. |\n| `storageKey` | `string` | \u2014 | localStorage key used for persisted sidebar widths. |\n| `persist` | `boolean` | `true` | Enables persistence when `storageKey` is provided. |\n| `defaultLeftWidth` / `defaultRightWidth` | `number` | `260` / `320` | Initial sidebar widths in pixels. |\n| `minLeftWidth` / `maxLeftWidth` | `number` | `160` / `520` | Left sidebar resize bounds. |\n| `minRightWidth` / `maxRightWidth` | `number` | `180` / `560` | Right sidebar resize bounds. |\n| `handleBackground` | `\"subtle\" \\| \"accent\" \\| \"contrast\" \\| \"none\"` | `\"subtle\"` | Resize strip background treatment. |\n| `handleHeight` | `\"short\" \\| \"medium\" \\| \"tall\" \\| \"full\"` | `\"medium\"` | Grip marker length before hover/focus expansion. |\n| `style` | `CSSProperties` | \u2014 | Pass `height: \"100%\"` when the layout should fill an available-height container. |\n\n## Accessibility\n\n- Resize handles use `role=\"separator\"`, arrow-key resizing, and current width values.\n- Left and right panes expose configurable aria labels.",
  "scroll-area": "## Overview\n\nClipped scrollable region.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `maxHeight` | `number \\| string` | `240` | Viewport height. |\n| `orientation` | `\"vertical\" \\| \"horizontal\" \\| \"both\"` | `\"vertical\"` | Scroll axes. |",
  "aspect-ratio": "## Overview\n\nLocks children to a fixed media ratio.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `ratio` | `number \\| string` | `\"16 / 9\"` | CSS aspect-ratio value. |",
  container: "## Overview\n\nCentered max-width content wrapper.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `size` | `ContainerSize` | `\"lg\"` | Max width token. |\n| `padded` | `boolean` | `true` | Horizontal padding. |",
  spacer: "## Overview\n\nInvisible spacing or flex grow gap.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `axis` | `\"x\" \\| \"y\" \\| \"both\"` | `\"y\"` | Direction. |\n| `size` | `number \\| string` | `16` | Fixed size. |\n| `flex` | `boolean \\| number` | `false` | Grow into available space. |",
  breadcrumb: "## Overview\n\nHierarchical location trail.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `BreadcrumbItem[]` | \u2014 | Trail entries. |\n| `separator` | `ReactNode` | `\"/\"` | Divider between items. |\n| `onNavigate` | `(id) => void` | \u2014 | Optional controlled navigation. |",
  pagination: "## Overview\n\nNumbered page controls.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `page` | `number` | \u2014 | Current page (1-based). |\n| `pageCount` | `number` | \u2014 | Total pages. |\n| `onPageChange` | `(page) => void` | \u2014 | Page change handler. |",
  "page-header": "## Overview\n\nPage title region with optional actions and breadcrumbs.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | \u2014 | Heading. |\n| `description` | `string` | \u2014 | Supporting copy. |\n| `actions` / `breadcrumbs` | `ReactNode` | \u2014 | Optional slots. |",
  toolbar: "## Overview\n\nDock/toolbar action strip.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `ReactNode` | \u2014 | Centre tools. |\n| `start` / `end` | `ReactNode` | \u2014 | Side clusters. |\n| `dense` | `boolean` | `false` | Compact density. |",
  "application-header": "## Overview\n\nResponsive application header composed from existing Opus primitives. It combines product branding, global search, shortcut guidance, application actions, notification badges, and the signed-in user profile.\n\n## When to use\n\n- Primary chrome for CRM, analytics, and administration workspaces.\n- Product shells that need global search and account actions in one consistent landmark.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `actions` | `ApplicationHeaderAction[]` | `[]` | Icon actions with optional notification counts. |\n| `brandSrc` | `string` | `/opus-logo.png` | Product logo source. |\n| `brandHref` | `string` | `/` | Brand destination. |\n| `searchValue` | `string` | `\"\"` | Controlled search value. |\n| `onSearchChange` | `(value) => void` | \u2014 | Called as global search changes. |\n| `searchShortcut` | `string[]` | `[\"⌘\", \"S\"]` | Shortcut displayed inside search and used to focus it. |\n| `showSearch` | `boolean` | `true` | Show the global search region. |\n| `profile` | `ApplicationHeaderProfile` | \u2014 | Signed-in user details and dropdown items. |\n| `onCreate` | `() => void` | \u2014 | Shows and handles the primary create action. |\n\n## Composition\n\nUses TextField, KeyboardShortcut, IconBadge, DropdownMenu, Divider, Tooltip, and UserProfileWidget. The header owns responsive layout but leaves application state and routing with its parent.\n\n## Accessibility\n\n- Uses a header landmark and a labelled navigation region for actions.\n- Command+S focuses and selects the global search field.\n- Search retains an accessible label while hiding visual field chrome.\n- Icon actions expose names and counts through IconBadge.\n- All interactive controls support visible keyboard focus.",
  "bottom-navigation": "## Overview\n\nMobile bottom destinations.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `BottomNavigationItem[]` | \u2014 | Destinations. |\n| `value` | `string` | \u2014 | Active id. |\n| `onChange` | `(id) => void` | \u2014 | Selection handler. |",
  "navigation-rail": "## Overview\n\nCompact vertical destination rail.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `NavigationRailItem[]` | \u2014 | Destinations. |\n| `collapsed` | `boolean` | `false` | Icon-only mode. |\n| `value` | `string` | \u2014 | Active id. |",
  "split-button": "## Overview\n\nPrimary action plus overflow menu.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `ReactNode` | \u2014 | Main button label. |\n| `actions` | `SplitButtonAction[]` | \u2014 | Menu items. |\n| `variant` | `ButtonVariant` | `\"primary\"` | Visual style. |",
  fab: "## Overview\n\nFloating action button.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `label` | `string` | \u2014 | Accessible/extended label. |\n| `icon` | `ReactNode` | \u2014 | Leading glyph. |\n| `extended` | `boolean` | `false` | Show label beside icon. |\n| `size` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Scale. |",
  tiles: "## Overview\n\nHorizontal row of neon glass quick-action tiles.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `TileItem[]` | \u2014 | Tiles with `id`, `label`, Font Awesome `icon` name, optional `tone`, and `onClick`. |\n| `layout` | `\"fill\" \\| \"fixed\"` | `\"fill\"` | Fill expands tiles to the row width when they fit; scrolls on overflow. Fixed keeps default tile sizes. |\n| `className` | `string` | \u2014 | Optional row wrapper class. |",
  "stat-tiles": "## Overview\n\nHorizontal row of dashboard metric stat tiles.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `StatTileItem[]` | \u2014 | Stat tiles with metric fields, icon name, optional `tone`, and `onClick`. |\n| `layout` | `\"fill\" \\| \"fixed\"` | `\"fill\"` | Fill expands tiles to the row width when they fit; scrolls on overflow. Fixed keeps default tile sizes. |\n| `className` | `string` | \u2014 | Optional row wrapper class. |",
  tile: "## Overview\n\nNeon glass quick-action tile with purple or blue glow accent.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `icon` | `string` | \u2014 | Font Awesome catalog icon name such as `user-plus`. |\n| `label` | `string` | \u2014 | Short action label. |\n| `tone` | `\"purple\" \\| \"blue\"` | `\"purple\"` | Accent colour. |\n| `onClick` | `() => void` | \u2014 | Click handler for button tiles. |\n| `href` | `string` | \u2014 | Optional link target; renders an anchor when set. |",
  "stat-tile": "## Overview\n\nDashboard metric tile with label, headline value, optional trend, comparison text, and a Font Awesome icon badge.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `label` | `string` | \u2014 | Metric title such as Total Contacts. |\n| `value` | `string` | \u2014 | Primary metric value. |\n| `icon` | `string` | \u2014 | Font Awesome catalog icon name. |\n| `tone` | `\"purple\" \\| \"blue\"` | `\"blue\"` | Neon glass accent colour. |\n| `trendValue` | `string` | \u2014 | Delta label such as `12.5%`. |\n| `trend` | `\"up\" \\| \"down\"` | \u2014 | Trend direction for colour and arrow. |\n| `comparison` | `string` | \u2014 | Supporting period copy such as `vs last 30 days`. |\n| `onClick` | `() => void` | \u2014 | Optional click handler. |",
  "property-inspector": "## Overview\n\nGrouped editable property sheet.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `PropertyInspectorItem[]` | \u2014 | Grouped editable rows. |\n| `searchable` | `boolean` | `false` | Shows a filter input. |\n| `onChange` | `(id, value) => void` | \u2014 | Edit handler. |",
  "filter-builder": "## Overview\n\nAND-joined filter condition builder.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `fields` | `string[]` | \u2014 | Selectable fields. |\n| `conditions` | `FilterCondition[]` | \u2014 | Current filters. |\n| `onChange` | `(conditions) => void` | \u2014 | Update handler. |",
  "query-builder": "## Overview\n\nAND/OR query group with editable rules.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `fields` | `string[]` | \u2014 | Selectable fields. |\n| `group` | `QueryGroup` | \u2014 | Combinator + rules. |\n| `onChange` | `(group) => void` | \u2014 | Update handler. |",
  "rule-builder": "## Overview\n\nOrdered policy rules with enable toggles and effects.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `rules` | `RuleDefinition[]` | \u2014 | Ordered rules. |\n| `onChange` | `(rules) => void` | \u2014 | Update handler. |",
  "permissions-matrix": "## Overview\n\nRole-by-resource access matrix.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `roles` | `string[]` | \u2014 | Row headers. |\n| `resources` | `string[]` | \u2014 | Column headers. |\n| `permissions` | `Record<string, Record<string, PermissionLevel>>` | \u2014 | Levels. |\n| `onChange` | `(role, resource, level) => void` | \u2014 | Update handler. |",
  "dual-list-builder": "## Overview\n\nSearchable dual-pane transfer list.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `available` | `DualListItem[]` | \u2014 | All options. |\n| `selectedIds` | `string[]` | \u2014 | Selected ids. |\n| `onChange` | `(selectedIds) => void` | \u2014 | Update handler. |",
  scheduler: "## Overview\n\nWeek-style timed event grid.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `events` | `SchedulerEvent[]` | \u2014 | Timed events. |\n| `days` | `string[]` | Mon–Fri | Column labels. |\n| `startHour` / `endHour` | `number` | `9` / `17` | Visible hours. |",
  "kanban-board": "## Overview\n\nColumn board with optional drag-and-drop cards.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `columns` | `KanbanColumn[]` | \u2014 | Columns and card ids. |\n| `cards` | `Record<string, KanbanCard>` | \u2014 | Card lookup. |\n| `onChange` | `(columns) => void` | \u2014 | Enables drag moves. |",
  calendar: "## Overview\n\nMonth calendar with selectable days, labelled timed events, and a day-detail overlay built on the shared `Modal` component.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `events` | `CalendarEvent[]` | `[]` | Day markers with optional `startTime`, `endTime`, tone, and title. |\n| `maxDayEvents` | `number` | `3` | Maximum events shown in a month cell; extra events collapse to `+N more`. |\n| `selectedDate` | `string` | \u2014 | `YYYY-MM-DD`. |\n| `onSelectDate` | `(date) => void` | \u2014 | Day click handler. |\n| `openDayOnSelect` | `boolean` | `true` | Open the shared Opus modal with schedule and booking form. |\n| `onBookEvent` | `(event) => void` | \u2014 | Called when a fake booking is added in the modal. |\n| `showMonthYearPicker` | `boolean` | `true` | Show month and year dropdowns in the header. |\n| `month` / `year` | `number` | \u2014 | Controlled visible month. |\n\n## CalendarEvent\n\n| Field | Type | Description |\n| --- | --- | --- |\n| `date` | `string` | `YYYY-MM-DD` day key. |\n| `title` | `string` | Event label. |\n| `startTime` | `string` | Optional `HH:mm` from time. |\n| `endTime` | `string` | Optional `HH:mm` to time. |\n| `tone` | `\"accent\" \\| \"success\" \\| \"warning\" \\| \"danger\"` | Marker colour. |",
  "resource-planner": "## Overview\n\nResource-by-hour assignment timeline.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `resources` | `ResourcePlannerResource[]` | \u2014 | Rows. |\n| `items` | `ResourcePlannerItem[]` | \u2014 | Timed assignments. |\n| `startHour` / `endHour` | `number` | `8` / `17` | Visible hours. |",
  "json-viewer": "## Overview\n\nRead-only JSON tree.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `unknown` | \u2014 | JSON-compatible value. |\n| `collapsedDepth` | `number` | `1` | Auto-expand depth. |",
  icon: "## Overview\n\nCatalog Font Awesome icon with size and tone.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `name` | `string` | — | Catalog icon name. |\n| `size` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Visual size. |\n| `tone` | tone enum | `\"default\"` | Colour token. |\n| `label` | `string` | — | Accessible name. |",
  "icon-badge": "## Overview\n\nNotification-style icon with an optional count badge for toolbars, headers, and app chrome.\n\n## When to use\n\n- Unread notifications, messages, or alerts in a top bar.\n- Compact action icons that need a numeric indicator.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `iconName` | `string` | — | Font Awesome catalog icon name such as `bell` or `envelope`. |\n| `label` | `string` | — | Accessible name; includes count when a badge is shown. |\n| `count` | `number` | `0` | Badge count. Hidden when zero unless `showZero` is true. |\n| `max` | `number` | `99` | Maximum value before showing `99+`. |\n| `size` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Icon and hit-target scale. |\n| `tone` | `IconTone` | `\"muted\"` | Icon colour. |\n| `urgency` | `IconBadgeUrgency` | `\"standard\"` | Badge colour: standard, danger, warning, success, or info. |\n| `showZero` | `boolean` | `false` | Render the badge when count is zero. |\n| `onClick` | `() => void` | — | When set, renders as a button. |\n\n## Accessibility\n\n- Exposes a single accessible label that includes the unread count.\n- Badge text is decorative (`aria-hidden`).\n\n## Related\n\n- [Icon](/documentation/components/icon)\n- [Badge](/documentation/components/badge)",
  spinner: "## Overview\n\nInline indeterminate loading spinner.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `size` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Size. |\n| `tone` | `\"accent\" \\| \"muted\" \\| \"inverse\"` | `\"accent\"` | Colour. |\n| `label` | `string` | `\"Loading\"` | Accessible status. |",
  clock: "## Overview\n\nLive analog clock with digital readout and optional date.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `size` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Face diameter. |\n| `showAnalog` | `boolean` | `true` | Show analog face. |\n| `showDigital` | `boolean` | `true` | Show digital time readout. |\n| `showDate` | `boolean` | `true` | Show formatted date. |",
  portal: "## Overview\n\nRender children into a host node outside the parent DOM hierarchy.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `ReactNode` | — | Content. |\n| `container` | `HTMLElement` | — | Optional explicit host. |\n| `disabled` | `boolean` | `false` | Render inline instead. |",
  "portal-host": "## Overview\n\nCreates a mount node and context for `Portal`.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `id` | `string` | `\"opus-portal-host\"` | Host element id. |\n| `children` | `ReactNode` | — | Tree that may portal. |",
  "visually-hidden": "## Overview\n\nHide content visually while exposing it to assistive technology.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `ReactNode` | — | Hidden content. |\n| `as` | `\"span\" \\| \"div\"` | `\"span\"` | Element type. |",
  "focus-trap": "## Overview\n\nTrap Tab focus inside a region while active.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `active` | `boolean` | `true` | Enable trap. |\n| `children` | `ReactNode` | — | Focusable region. |",
  "keyboard-shortcut": "## Overview\n\nVisual shortcut chips for menus and docs.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `keys` | `string[]` | — | Key labels. |\n| `size` | `\"sm\" \\| \"md\"` | `\"md\"` | Chip size. |",
  "hotkey-manager": "## Overview\n\nContext for registering global hotkeys via `useHotkey`.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `enabled` | `boolean` | `true` | Listen for shortcuts. |\n| `children` | `ReactNode` | — | App subtree. |",
  "copy-button": "## Overview\n\nCopy a string to the clipboard with confirmation feedback.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | — | Text to copy. |\n| `label` | `string` | `\"Copy\"` | Idle label. |\n| `copiedLabel` | `string` | `\"Copied\"` | Success label. |",
  clipboard: "## Overview\n\nClipboard provider exposing `useClipboard()` write/read helpers.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `ReactNode` | — | Consumer tree. |",
  "theme-provider": "## Overview\n\nAlias of `OpusThemeProvider` for setting theme context and `data-theme`.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `theme` | `Theme` | — | Active theme. |\n| `applyToDocument` | `boolean` | `true` | Set root `data-theme`. |",
  "theme-switcher": "## Overview\n\nLight/dark switcher control built on `ThemeToggleField`.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `Theme` | — | Current theme. |\n| `onChange` | `(theme) => void` | — | Theme handler. |\n| `label` | `string` | `\"Theme\"` | Field label. |",
  "resize-observer": "## Overview\n\nRender-prop / hook wrapper around `ResizeObserver`.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `(size) => ReactNode` | — | Size renderer. |\n| `onResize` | `(size) => void` | — | Optional callback. |",
  "intersection-observer": "## Overview\n\nRender-prop / hook wrapper around `IntersectionObserver`.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `(visible) => ReactNode` | — | Visibility renderer. |\n| `threshold` | `number` | `0.25` | Intersection threshold. |",

  statistic: "## Overview\n\nLightweight labelled statistic with optional trend.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `label` | `string` | \u2014 | Caption. |\n| `value` | `string` | \u2014 | Primary figure. |\n| `prefix` | `string` | \u2014 | Optional prefix. |\n| `suffix` | `string` | \u2014 | Optional suffix. |\n| `trend` | `StatisticTrend` | \u2014 | up, down, or flat. |\n| `trendLabel` | `string` | \u2014 | Trend copy. |",
  "file-upload": "## Overview\n\nFile picker with styled drop zone.\n\n## When to use\n\n- Document and image uploads.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `onChange` | `(event) => void` | \u2014 | Selection handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "image-crop-upload": "## Overview\n\nProfile photo uploader with a circular crop mask. Users drag to reposition, zoom in and out, then apply a circular crop before upload.\n\n## When to use\n\n- Account profile photo capture.\n- Avatar uploads that need framing before save.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Cropped preview URL after apply. |\n| `onChange` | `(previewUrl) => void` | \u2014 | Called with the cropped preview URL. |\n| `onCrop` | `({ file, previewUrl }) => void` | \u2014 | Called with the cropped `File` and preview URL. |\n| `viewportSize` | `number` | `240` | Circular editor diameter in pixels. |\n| `outputSize` | `number` | `256` | Exported crop size in pixels. |\n| `minZoom` / `maxZoom` | `number` | `1` / `3` | Zoom range. |\n| `uploadLabel` | `string` | `\"Browse image\"` | Browse action label. |\n| `cropButtonLabel` | `string` | `\"Apply crop\"` | Confirm crop label. |\n| `changeButtonLabel` | `string` | `\"Change photo\"` | Replace photo label. |\n\n## Accessibility\n\n- Wrapped in `FieldShell`.\n- Crop viewport exposes an application region with drag and zoom controls.",
  "hidden-input": "## Overview\n\nHidden form field.\n\n## When to use\n\n- Tokens and non-editable ids.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `name` | `string` | \u2014 | Field name. |\n| `value` | `string` | \u2014 | Submitted value. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.\n- Not exposed to assistive tech.",
  "image-gallery": "## Overview\n\nGrid of lightbox thumbnails.\n\n## When to use\n\n- Photo grids.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `images` | `GalleryImage[]` | \u2014 | Items. |\n| `columns` | `2 \\| 3 \\| 4` | \u2014 | Grid columns. |\n\n## Accessibility\n\n- `aria-label` on gallery container.",
  "image-thumbnail": "## Overview\n\nThumbnail with optional lightbox.\n\n## When to use\n\n- Single image previews.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `image` | `GalleryImage` | \u2014 | Image. |\n| `size` | `ImageThumbnailSize` | \u2014 | Scale. |",
  "lightbox": "## Overview\n\nFull-screen image viewer.\n\n## When to use\n\n- Enlarge thumbnails.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `image` | `GalleryImage` | \u2014 | Image. |\n| `trigger` | `ReactNode` | \u2014 | Optional trigger. |\n\n## Accessibility\n\n- Focus trap; Escape dismisses.",
  "mega-menu": "## Overview\n\nLarge grouped navigation panel with optional featured callout.\n\n## When to use\n\n- Product navigation with grouped destinations.\n- Documentation hubs with a promotional sidebar.\n- Standalone menu surfaces outside a full app menu bar.\n\n## Data\n\nPass a `menus` array. Each entry defines one top-level trigger and its panel content:\n\n- `id` and `label` identify the menu trigger.\n- `sections` defines the column count; each section is one column with a title and `items` rows.\n- `featured` is an optional promotional sidebar with `eyebrow`, `title`, `description`, and `actionLabel`.\n\nUse `staticPanel` to render a single menu panel inline without a trigger (for docs and previews).\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `menus` | `MegaMenuConfig[]` | \u2014 | Primary data source; pass one item for a single menu. |\n| `sections` | `MegaMenuSection[]` | \u2014 | Legacy fallback when `menus` is omitted. |\n| `featured` | `MegaMenuFeatured` | \u2014 | Legacy fallback featured panel for a single menu. |\n| `density` | `SurfaceDensity` | `\"comfortable\"` | Spacing scale. |\n| `staticPanel` | `boolean` | `false` | Render the panel inline without a trigger button. |\n| `open` | `boolean` | \u2014 | Controlled open state for standalone dropdown usage. |\n\n## Accessibility\n\n- Menu trigger exposes `aria-haspopup`, `aria-expanded`, and `aria-controls` when not using `staticPanel`.\n- Escape and outside-click dismissal are configurable.\n\n## Related\n\n- [Top navigation](/documentation/components/top-navigation)",
  "model-gallery": "## Overview\n\nGrid of 3D asset thumbnails.\n\n## When to use\n\n- Browsing game props, enemies, and environment assets.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `assets` | `ModelAsset[]` | \u2014 | Model items. |\n| `columns` | `2 \\| 3 \\| 4` | `4` | Grid columns. |\n| `thumbnailSize` | `ModelThumbnailSize` | `\"small\"` | Preview scale. |\n\n## Accessibility\n\n- Each thumbnail opens a labelled dialog for the selected model.",
  "model-lightbox": "## Overview\n\nFull-screen 3D model viewer.\n\n## When to use\n\n- Inspecting a single GLB model from a thumbnail or action button.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `asset` | `ModelAsset` | \u2014 | Model metadata and source. |\n| `trigger` | `ReactNode` | \u2014 | Optional trigger content. |\n| `dismissOnBackdrop` | `boolean` | `true` | Close when clicking the backdrop. |\n\n## Accessibility\n\n- Uses a dialog role, focus restore, and optional Escape dismiss.",
  "model-thumbnail": "## Overview\n\nCompact 3D asset preview.\n\n## When to use\n\n- Single asset cards and gallery items.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `asset` | `ModelAsset` | \u2014 | Model metadata and source. |\n| `size` | `ModelThumbnailSize` | `\"medium\"` | Preview scale. |\n| `openInLightbox` | `boolean` | `true` | Opens full model preview on click. |",
  "model-viewer": "## Overview\n\nInteractive 3D model preview.\n\n## When to use\n\n- Showing GLB assets inline with orbit controls and automatic rotation.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `asset` | `ModelAsset` | \u2014 | Model metadata and source. |\n| `autoRotate` | `boolean` | `true` | Rotate the asset automatically. |\n| `cameraControls` | `boolean` | `true` | Allow pointer orbit and zoom. |\n\n## Accessibility\n\n- Uses `alt` metadata for the model-viewer element and visible captions.",
  "modal": "## Overview\n\nCentred overlay for longer content.\n\n## When to use\n\n- Forms and multi-step flows.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `open` | `boolean` | \u2014 | Visible. |\n| `title` | `string` | \u2014 | Heading. |\n| `size` | `ModalSize` | `\"medium\"` | Width. |\n| `onClose` | `() => void` | \u2014 | Close handler. |\n\n## Accessibility\n\n- Focus trap; Tab cycles within modal.",
  "month-picker": "## Overview\n\nNative month input (`type=\"month\"`).\n\n## When to use\n\n- Month selection with browser-native picker.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Input value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "number-input": "## Overview\n\nNumber field with stepper buttons.\n\n## When to use\n\n- Quantities and bounded numbers.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `number` | \u2014 | Value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `min` | `number` | \u2014 | Minimum. |\n| `max` | `number` | \u2014 | Maximum. |\n| `step` | `number` | `1` | Step size. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.\n- Steppers disable at min/max.",
  "panel": "## Overview\n\nStructured page section.\n\n## When to use\n\n- Settings groups and docs sections.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | \u2014 | Heading. |\n| `description` | `string` | \u2014 | Subtitle. |\n| `bordered` | `boolean` | `true` | Outer frame and shadow. Turn off for unframed section layouts. |\n| `divided` | `boolean` | `true` | Header/body/footer separators. |\n| `density` | `\"comfortable\" \\| \"compact\"` | `\"comfortable\"` | Padding scale. |\n| `tone` | `SurfaceTone` | `\"default\"` | Accent colour for the frame. |\n| `children` | `ReactNode` | \u2014 | Body. |\n\n## Accessibility\n\n- Semantic `section` with header/footer.",
  "section": "## Overview\n\nResponsive page layout primitive with rows and columns.\n\n## When to use\n\n- Page-level layouts that stack on mobile and expand on tablet/desktop.\n- Sidebar plus multi-column main areas.\n- Equal-width columns that stay on one row and fill the available width.\n\n## Mental model\n\n- `Section` \u2014 vertical stack of rows with optional title.\n- `Section.Row` \u2014 one responsive band configured with `sidebar` and `columns`.\n- `Section.Column` \u2014 optional slot for custom span or width.\n\n## Configuration\n\n| Setting | Values | Description |\n| --- | --- | --- |\n| `sidebar` | `none`, `left`, `right` | Optional sidebar track beside the main area. |\n| `columns` | `1`\u2013`5` | Number of equal content columns in the main area. |\n| `stackBelow` | `mobile`, `tablet`, `never` | When layouts collapse to one column. |\n| `sidebarRatio` | `1:2`, `1:3`, `2:3` | Sidebar width vs main area when a sidebar is active. |\n\nWhen `sidebar` is set with `columns` greater than 1, the main area uses a nested `Section.Row` for the content columns.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `title` | `string` | \u2014 | Section heading. |\n| `description` | `string` | \u2014 | Section subtitle. |\n| `gap` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Vertical gap between rows. |\n| `sidebar` | `\"none\" \\| \"left\" \\| \"right\"` | `\"none\"` | Sidebar placement on `Section.Row`. |\n| `columns` | `1`\u2013`5` | `1` | Equal content columns. |\n| `stackBelow` | `\"mobile\" \\| \"tablet\" \\| \"never\"` | `\"mobile\"` | Collapse breakpoint. |\n| `template` | `Partial<Record<breakpoint, string>>` | \u2014 | Custom CSS grid templates per breakpoint. |\n\n## Accessibility\n\n- Semantic `section` with optional `h2` heading.\n\n## Related\n\n- [Panel](/documentation/components/panel)\n- [Card](/documentation/components/card)",
  "password-input": "## Overview\n\nPassword variant of TextField.\n\n## When to use\n\n- Collecting password values.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `placeholder` | `string` | \u2014 | Placeholder. |\n| `type` | `\"password\"` | `\"password\"` | Fixed input type. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "popover": "## Overview\n\nAnchored floating panel.\n\n## When to use\n\n- Inline help and compact forms.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `trigger` | `ReactNode` | \u2014 | Trigger. |\n| `title` | `string` | \u2014 | Optional title. |\n| `placement` | `PopoverPlacement` | `\"bottom\"` | Side. |\n\n## Accessibility\n\n- `aria-expanded` on trigger.",
  "radio-group": "## Overview\n\nGrouped radio options with shared selection state.\n\n## When to use\n\n- Mutually exclusive choices.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Selected value. |\n| `onChange` | `(value: string) => void` | \u2014 | Selection handler. |\n| `options` | `ChoiceOption[]` | \u2014 | Radio options. |\n| `shape` | `\"round\" \\| \"square\"` | `\"round\"` | Indicator shape. |\n| `size` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Radio indicator scale. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "chip-input": "## Overview\n\nTokenised text input that converts typed values into removable chips. Also known as tag input, token input, or pills input.\n\n## When to use\n\n- Email recipients, user permissions, and keyword fields.\n- Labels, categories, and skills where values should stay visible.\n- Any repeated free-text values that benefit from compact pill display.\n\n## Presets\n\nBuild specialised flows on the same component:\n\n- **Chip input** — generic multi-value entry.\n- **Tag input** — labels and keywords.\n- **Token input** — recipients, users, and permissions.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string[]` | \u2014 | Current chips. |\n| `onChange` | `(value: string[]) => void` | \u2014 | Chip list handler. |\n| `placeholder` | `string` | \u2014 | Shown when empty. |\n| `variant` | `\"filled\" \\| \"outlined\" \\| \"soft\" \\| \"glass\" \\| \"gradient\"` | `\"soft\"` | Chip visual style. |\n| `readOnly` | `boolean` | `false` | Show chips without editing. |\n| `disabled` | `boolean` | `false` | Disables interaction. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Interaction\n\n- Press **Enter**, **Comma**, or **Tab** to commit the current text as a chip.\n- Press **Backspace** on an empty input to remove the last chip.\n- Click **\u00d7** on a chip to remove it.\n\n## Chip variants\n\n| Variant | Description |\n| --- | --- |\n| Filled | Solid chip background. |\n| Outlined | Border-only chips. |\n| Soft | Accent-tinted fill. |\n| Glass | Frosted translucent chips. |\n| Gradient | Purple/blue Opus gradient border. |\n\n## States\n\nDefault, hover, focus, disabled, error, and read-only are supported on the field and chips.\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Chips expose remove buttons with descriptive `aria-label` values.\n\n## Related\n\n- [Text input](/documentation/components/text-input)\n- [Select](/documentation/components/select)",
  "choice-chips": "## Overview\n\nSelectable chip group for compact single or multiple choice decisions.\n\n## When to use\n\n- Interest, preference, filter, and category pickers.\n- Small option sets where chips are quicker than a select.\n- Multi-select choices that should remain visible without opening a menu.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `options` | `ChoiceOption[]` | \u2014 | Chip options with `label`, `value`, and optional `disabled`. |\n| `value` | `string \\| string[]` | \u2014 | Selected value for single mode, or selected values for multiple mode. |\n| `onChange` | `(value: string \\| string[]) => void` | \u2014 | Selection handler. |\n| `selectionMode` | `\"multiple\" \\| \"single\"` | `\"multiple\"` | Allows multiple chips or one radio-style choice. |\n| `variant` | `\"filled\" \\| \"outlined\" \\| \"soft\" \\| \"glass\"` | `\"soft\"` | Chip visual style. |\n| `disabled` | `boolean` | `false` | Disables all chips. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n\n## Accessibility\n\n- Multiple mode uses pressed button semantics.\n- Single mode exposes a radiogroup with radio-style chip semantics.\n- Wrapped in `FieldShell` for label, help, error, and required wiring.",
  "range-slider": "## Overview\n\nRange slider with value display.\n\n## When to use\n\n- Volume, opacity, approximate values.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `number` | \u2014 | Value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `min` | `number` | \u2014 | Min. |\n| `max` | `number` | \u2014 | Max. |\n| `step` | `number` | `1` | Step. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "reset-button": "## Overview\n\nForm reset button using `Button` with `type=\"reset\"`.\n\n## When to use\n\n- Forms where users should restore default field values.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `ReactNode` | \u2014 | Button label or content. |\n| `variant` | `ButtonVariant` | `\"primary\"` | Visual style: primary, secondary, success, danger, warning, info, light, dark, link. |\n| `disabled` | `boolean` | `false` | Disables interaction. |\n| `type` | `\"button\" \\| \"submit\" \\| \"reset\"` | `\"button\"` | Native button type. |",
  "search-input": "## Overview\n\nSearch variant of TextField with a built-in magnifying glass prefix icon.\n\n## When to use\n\n- Collecting search values.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `placeholder` | `string` | \u2014 | Placeholder. |\n| `type` | `\"search\"` | `\"search\"` | Fixed input type. |\n| `size` | `\"sm\" \\| \"md\" \\| \"lg\"` | `\"md\"` | Control density: compact, comfortable, or spacious padding. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Search icon is decorative (`aria-hidden`).\n- Labels associate with controls via `htmlFor` / `id`.",
  "select": "## Overview\n\nDropdown select.\n\n## When to use\n\n- Choosing from predefined options.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Selected value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `options` | `string[]` | \u2014 | Options list. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "show-more": "## Overview\n\nClamp long text with toggle.\n\n## When to use\n\n- Truncated descriptions.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `ReactNode` | \u2014 | Content. |\n| `maxLines` | `number` | `3` | Clamp lines. |\n\n## Accessibility\n\n- Toggle has `aria-expanded`.",
  "sidebar": "## Overview\n\nIcon-led side navigation surface matching the Opus documentation menu.\n\n## When to use\n\n- App and docs left navigation.\n- Labs/widgets where the container chrome is supplied separately.\n\n## Data\n\nPass a `menu` array to render the sidebar from configuration. Use `defaultActiveItem` when the Sidebar should manage its own selected item, or `activeItem` when the parent should fully control selection. The selected item bubbles up through `onSelect`.\n\n```tsx\nconst [lastAction, setLastAction] = useState(\"Waiting for action\");\n\nconst handleMenuSelect = (item) => {\n  setLastAction(`Menu callback: ${item.label}`);\n};\n\nconst handleItemSelect = (label) => {\n  setLastAction(`Item callback: ${label}`);\n};\n\nconst menu = [\n  {\n    id: \"overview\",\n    label: \"Overview\",\n    icon: \"grid-2\",\n    onSelect: () => handleItemSelect(\"Overview\"),\n  },\n  {\n    type: \"group\",\n    id: \"library-group\",\n    label: \"Library\",\n    icon: \"layer-group\",\n    children: [\n      {\n        id: \"library\",\n        label: \"Components\",\n        icon: \"cube\",\n        onSelect: () => handleItemSelect(\"Components\"),\n      },\n      {\n        id: \"templates\",\n        label: \"Templates\",\n        icon: \"copy\",\n        onSelect: () => handleItemSelect(\"Templates\"),\n      },\n    ],\n  },\n];\n\nreturn (\n  <Sidebar\n    menu={menu}\n    defaultActiveItem=\"library\"\n    persistState\n    onSelect={handleMenuSelect}\n  />\n);\n```\n\nUse `renderIcon` when your menu stores icon keys as strings. The JSX subcomponents (`SidebarNav`, `SidebarLink`, and `SidebarGroup`) are still available for custom composition. Give child links an `itemId` to opt into the same active matching and parent `onSelect` callback flow, or pass `onSelect` directly to a `SidebarLink` for a per-link child callback.\n\n## Persistence\n\nSet `persistState` to store the selected item and open groups in localStorage. By default the key is generated from a hash of the menu structure and nav label, so multiple data-driven sidebars do not collide. Pass `storageKey` when you need an explicit key, especially for JSX children-only sidebars.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `menu` | `SidebarMenuItem[]` | \u2014 | Data-driven navigation items and groups. |\n| `activeItem` | `string` | \u2014 | Controlled active menu item id. |\n| `defaultActiveItem` | `string` | \u2014 | Initial active item when Sidebar manages selection internally. |\n| `onSelect` | `(item) => void` | \u2014 | Shared callback for menu items and child links with `itemId`. |\n| `persistState` | `boolean` | `false` | Persists selected item and group open state. |\n| `storageKey` | `string` | hashed menu | Explicit persistence key for this sidebar instance. |\n| `renderIcon` | `(icon) => ReactNode` | \u2014 | Renders string icon keys from menu data. |\n| `itemId` | `string` | \u2014 | `SidebarLink` id for child callbacks and active matching. |\n| `side` | `SidebarSide` | `\"left\"` | Position. |\n| `collapsed` | `boolean` | \u2014 | Icon-only mode. |\n| `icon` | `ReactNode \\| string` | \u2014 | Optional icon on menu items, `SidebarLink`, and `SidebarGroup`. |\n\n## Accessibility\n\n- Header is `h2`; groups labelled when collapsed.",
  "skeleton": "## Overview\n\nLoading placeholder.\n\n## When to use\n\n- Async content loading.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `variant` | `SkeletonVariant` | `\"text\"` | Shape. |\n| `lines` | `number` | `3` | Line count. |\n\n## Accessibility\n\n- `aria-busy=\"true\"` on container.",
  "alert": "## Overview\n\nDismissible inline banner.\n\n## When to use\n\n- Form errors and success.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `status` | `AlertStatus` | `\"error\"` | Tone. |\n| `title` | `string` | \u2014 | Heading. |\n| `description` | `string` | \u2014 | Detail. |\n\n## Accessibility\n\n- `role=\"alert\"` or `role=\"status\"`.",
  "submit-button": "## Overview\n\nForm submission button using `Button` with `type=\"submit\"`.\n\n## When to use\n\n- End of forms to commit user input.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `children` | `ReactNode` | \u2014 | Button label or content. |\n| `variant` | `ButtonVariant` | `\"primary\"` | Visual style: primary, secondary, success, danger, warning, info, light, dark, link. |\n| `disabled` | `boolean` | `false` | Disables interaction. |\n| `type` | `\"button\" \\| \"submit\" \\| \"reset\"` | `\"button\"` | Native button type. |",
  "switch": "## Overview\n\nToggle switch for on/off settings.\n\n## When to use\n\n- Settings that take effect immediately.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `checked` | `boolean` | \u2014 | Controlled on state. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.\n- Switch uses switch semantics with associated label.",
  "table": "## Overview\n\nResponsive data table.\n\n## When to use\n\n- Read-only tabular data.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `columns` | `TableColumn[]` | \u2014 | Columns. |\n| `rows` | `TableRow[]` | \u2014 | Rows. |\n| `emptyMessage` | `string` | \u2014 | Empty copy. |\n\n## Accessibility\n\n- Empty cell uses `role=\"status\"`.",
  "tabs": "## Overview\n\nTabbed content navigation.\n\n## When to use\n\n- Related views without routing.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `items` | `TabItem[]` | \u2014 | Tabs. |\n| `value` | `string` | \u2014 | Active tab. |\n\n## Accessibility\n\n- Arrow keys move tab focus.",  "text-input": "## Overview\n\nSingle-line text input.\n\n## When to use\n\n- Names, titles, short text.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `placeholder` | `string` | \u2014 | Placeholder. |\n| `type` | `\"text\"` | `\"text\"` | Input type. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "textarea": "## Overview\n\nMulti-line text with optional character limit.\n\n## When to use\n\n- Descriptions and comments.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `maxChars` | `number` | \u2014 | Max length. |\n| `placeholder` | `string` | \u2014 | Placeholder. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.\n- Character count in `aria-describedby` when limited.",
  "note-composer": "## Overview\n\nInset note entry box for CRM panels, comment threads, and quick-capture forms. Includes attachment, mention, and a reusable `EmojiPicker` popover plus a primary save button.\n\n## When to use\n\n- Notes tabs on activity feeds.\n- Inline comment capture without a full field label shell.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Controlled textarea value. |\n| `defaultValue` | `string` | `\"\"` | Initial value when uncontrolled. |\n| `onChange` | `(value) => void` | \u2014 | Called when the textarea changes. |\n| `onSave` | `(value) => void` | \u2014 | Called with trimmed text when Save is pressed. |\n| `placeholder` | `string` | `\"Add a note...\"` | Textarea placeholder. |\n| `saveButtonLabel` | `string` | `\"Save Note\"` | Primary action label. |\n| `showAttach` | `boolean` | `true` | Show attachment toolbar button. |\n| `showMention` | `boolean` | `true` | Show mention toolbar button. |\n| `showEmoji` | `boolean` | `true` | Show emoji picker trigger in the toolbar. |\n| `onAttachClick` | `() => void` | \u2014 | Attachment button callback. |\n| `onMentionClick` | `() => void` | \u2014 | Mention button callback. |\n| `onEmojiSelect` | `(emoji) => void` | \u2014 | Called after an emoji is inserted into the note. |\n\n## Related\n\n- [Emoji picker](/documentation/components/emoji-picker)",
  "theme-toggle": "## Overview\n\nLight/dark theme switch.\n\n## When to use\n\n- App theme preference.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `\"light\" \\| \"dark\"` | \u2014 | Theme. |\n| `onChange` | `(theme) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.\n- `aria-pressed` on theme buttons.",
  "accent-color-picker": "## Overview\n\nPreset accent colour swatches for branding.\n\n## When to use\n\n- Let users pick an app accent colour from a curated palette.\n- Pair with `createAccentStyle()` to apply CSS custom properties.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Selected hex colour. |\n| `onChange` | `(value) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"flagged\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label wiring.\n- Swatches use `role=\"radiogroup\"` with `aria-checked` on each option.\n\n## Related\n\n- [Theme toggle](/documentation/components/theme-toggle)\n- [Colour picker](/documentation/components/color-picker)",
  "icon-picker": "## Overview\n\nSearchable Font Awesome icon picker with frosted icon badges.\n\n## When to use\n\n- Let users choose an icon from the solid Font Awesome set.\n- Pair with dashboard cards, metric tiles, and other icon slots.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Selected Font Awesome `iconName` such as `chart-column`. |\n| `onChange` | `(value) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `searchPlaceholder` | `string` | `\"Search icons\"` | Placeholder for the filter field. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label wiring.\n- Trigger exposes `aria-expanded` and listbox options use `aria-selected`.\n\n## Related\n\n- [Stat card](/documentation/components/stat-card)\n- [Metric tile](/documentation/components/metric-tile)",
  "emoji-picker": "## Overview\n\nReusable categorized emoji picker with search, rendered as a popover from any custom trigger.\n\n## When to use\n\n- Note composers, chat inputs, and comment fields.\n- Any toolbar action that inserts emoji into text.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `trigger` | `ReactNode` | \u2014 | Button or control that opens the picker. |\n| `onSelect` | `(emoji) => void` | \u2014 | Called when an emoji is chosen. |\n| `placement` | `\"top\" \\| \"bottom\"` | `\"top\"` | Popover position relative to the trigger. |\n| `searchPlaceholder` | `string` | `\"Search emojis\"` | Search field placeholder. |\n| `open` | `boolean` | \u2014 | Controlled open state. |\n| `defaultOpen` | `boolean` | `false` | Initial open state when uncontrolled. |\n| `onOpenChange` | `(open) => void` | \u2014 | Called when the popover opens or closes. |\n| `closeOnOutside` | `boolean` | `true` | Close when clicking outside. |\n| `closeOnEscape` | `boolean` | `true` | Close on Escape key. |\n\n## Accessibility\n\n- Trigger receives `aria-expanded` and `aria-haspopup`.\n- Picker panel uses `role=\"dialog\"` with a search field and emoji listbox.\n- Category bar uses `role=\"tablist\"`.\n\n## Related\n\n- [Note composer](/documentation/components/note-composer)\n- [Popover](/documentation/components/popover)",
  "time-picker": "## Overview\n\nNative time input (`type=\"time\"`).\n\n## When to use\n\n- Time selection with browser-native picker.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Input value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "toast": "## Overview\n\nFloating notification via ToastProvider.\n\n## When to use\n\n- Transient action feedback.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `status` | `AlertStatus` | \u2014 | Tone. |\n| `title` | `string` | \u2014 | Message. |\n\n## Accessibility\n\n- Use with `ToastProvider` and `useToast()`.\n\n## Related\n\n- [Alert](/documentation/components/alert)",
  "tooltip": "## Overview\n\nHelp icon with popup on hover, focus, or click.\n\n## When to use\n\n- Supplementary help beside labels.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `content` | `string` | \u2014 | Tooltip text. |\n| `label` | `string` | `\"More information\"` | Trigger label. |\n\n## Accessibility\n\n- `role=\"tooltip\"` and `aria-describedby` on trigger.",
  "top-navigation": "## Overview\n\nUnified app-style top navigation with normal dropdowns and a single MegaMenu item.\n\n## When to use\n\n- Desktop app chrome with top-level items such as App, File, Edit, View, Window, and Help.\n- Navigation where one top item needs a rich mega panel while the rest stay compact.\n\n## Data\n\nPass a single `menus` array to define the full bar in order. Each entry is one top-level label (`App`, `File`, `Edit`, …):\n\n| Field | Dropdown (`type: \"dropdown\"`) | Mega panel (`type: \"mega\"`) |\n| --- | --- | --- |\n| `id` | Menu id for `activeMenu` | Menu id for `activeMenu` |\n| `label` | Bar trigger text | Bar trigger text |\n| `items` | Flat dropdown rows | \u2014 |\n| `sections` | \u2014 | Grouped mega menu columns |\n| `featured` | \u2014 | Optional promotional sidebar |\n\n```tsx\nconst menus = [\n  { type: \"dropdown\", id: \"app\", label: \"App\", items: [...] },\n  { type: \"mega\", id: \"edit\", label: \"Edit\", sections: [...], featured: {...} },\n];\n\n<TopNavigation menus={menus} />\n```\n\nUse `activeMenu` + `onActiveMenuChange` for controlled open state.\n\nHandle link clicks with `onSelect` on `TopNavigation` for one shared handler, or `onSelect` on individual dropdown `items` / mega menu rows for per-link callbacks.\n\n```tsx\nconst handleSelect = (menuId, item) => setLastAction(`${menuId}: ${item.label}`);\n\n<TopNavigation menus={menus} onSelect={handleSelect} />\n```\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `menus` | `TopNavigationBarMenu[]` | default bar | Defines the full top navigation in order. |\n| `activeMenu` | `string \\| null` | `null` | Controlled active top menu id. |\n| `density` | `SurfaceDensity` | `\"comfortable\"` | Spacing scale. |\n| `showShortcuts` | `boolean` | `true` | Show keyboard shortcuts on dropdown items. |\n| `closeOnOutside` | `boolean` | `true` | Close menus on outside click. |\n| `closeOnEscape` | `boolean` | `true` | Close menus on Escape. |\n| `closeOnSelect` | `boolean` | `true` | Close menus after a link is selected. |\n| `onActiveMenuChange` | `(menuId) => void` | \u2014 | Called when the open menu changes. |\n| `onSelect` | `(menuId, item) => void` | \u2014 | Called when a dropdown or mega menu link is selected. |\n| `children` | `ReactNode` | \u2014 | Optional custom bar composition instead of `menus`. |\n\n## Accessibility\n\n- The bar uses a labelled `nav` landmark.\n- Dropdown and mega menu triggers expose expanded state and keyboard dismissal.\n\n## Related\n\n- [Mega menu](/documentation/components/mega-menu)\n- [Dropdown menu](/documentation/components/dropdown-menu)",
  "url-input": "## Overview\n\nURL variant of TextField.\n\n## When to use\n\n- Collecting url values.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `placeholder` | `string` | \u2014 | Placeholder. |\n| `type` | `\"url\"` | `\"url\"` | Fixed input type. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
  "week-picker": "## Overview\n\nNative week input (`type=\"week\"`).\n\n## When to use\n\n- Week selection with browser-native picker.\n\n## Props\n\n| Prop | Type | Default | Description |\n| --- | --- | --- | --- |\n| `value` | `string` | \u2014 | Input value. |\n| `onChange` | `(event) => void` | \u2014 | Change handler. |\n| `mode` | `\"stacked\" \\| \"flagged\"` | `\"stacked\"` | Layout mode for label and control. |\n| `labelPosition` | `\"left\" \\| \"right\"` | `\"left\"` | Label placement in flagged mode. |\n| `error` | `string` | \u2014 | Validation message; sets `aria-invalid` when present. |\n| `help` | `string` | \u2014 | Supplementary help text linked via `aria-describedby`. |\n| `required` | `boolean` | `false` | Marks the field as required for assistive tech. |\n\n## Accessibility\n\n- Wrapped in `FieldShell` for label, help, error, and required wiring.\n- Labels associate with controls via `htmlFor` / `id`.",
};

export function getComponentDocumentationMarkdown(slug: ControlSlug): string | null {
  const labDocumentationAliases: Partial<Record<ControlSlug, ControlSlug>> = {
    "lab-sidebar": "sidebar",
    "lab-test-layout": "three-pane-layout",
    "lab-user-profile": "user-profile",
  };
  const documentationSlug = labDocumentationAliases[slug] ?? slug;
  const markdown = componentDocumentation[documentationSlug];
  if (markdown) {
    return markdown;
  }

  const control = getControl(slug);
  if (!control) {
    return null;
  }

  if (control.category === "graphs") {
    return [
      "## Overview",
      "",
      `${control.title} is rendered with the shared \`Chart\` component.`,
      "",
      "## When to use",
      "",
      control.description,
      "",
      "## Props",
      "",
      "| Prop | Type | Default | Description |",
      "| --- | --- | --- | --- |",
      "| `variant` | `ChartVariant` | — | Selects the visual chart type. |",
      "| `data` | `ChartDatum[]` | demo data | Category data used by bars, radial, funnel, and point charts. |",
      "| `series` | `ChartSeries[]` | demo series | Multi-series data used by grouped, stacked, multi-line, and area charts. |",
      "| `palette` | `ChartPalette` | `\"opus\"` | Opus, cool, warm, or mono palette. |",
      "| `height` | `number` | `280` | Chart viewport height in pixels. |",
      "| `maximise` | `boolean` | `false` | Allows wide chart types such as bars, lines, areas, and point charts to fill available space. |",
      "| `showAxis` | `boolean` | `false` | Shows data-driven X and Y axes on cartesian charts. |",
      "| `xAxisLabel` | `string` | — | Optional X axis title. |",
      "| `yAxisLabel` | `string` | — | Optional Y axis title. |",
      "| `highlightLabel` | `string` | — | Optional highlighted category for vertical bar charts. |",
      "| `showGrid` | `boolean` | `false` | Shows chart grid lines where relevant. |",
      "| `showLegend` | `boolean` | `true` | Shows series/category legend. |",
      "| `showValues` | `boolean` | `false` | Shows visible value labels where supported. |",
      "",
      "## Accessibility",
      "",
      "- Renders an SVG with `role=\"img\"` and an accessible label from the chart title.",
      "- Keep source data available in adjacent tables when exact numeric values matter.",
    ].join("\n");
  }

  return [
    "## Overview",
    "",
    control.description,
  ].join("\n");
}
